('spanish:x-1-listening-and-dictation:mcq:ce2cb065', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Tengo un hermano mayor y una hermana menor.\" data-listen></span><br>Listen. What does the speaker say about their siblings?", "options": ["An older brother and a younger sister", "A younger brother and an older sister", "Two older brothers and no sisters at all", "An older sister who lives with a younger brother in Madrid"]}'::jsonb, '{"answer": 0, "explain": "mayor = older, menor = younger. Trap B simply swaps the two around; trap D adds invented detail."}'::jsonb),
('spanish:x-1-listening-and-dictation:mcq:8fbc4515', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Normalmente hago mis deberes después de cenar.\" data-listen></span><br>Listen. When does the speaker usually do their homework?", "options": ["After dinner", "Before dinner", "Straight after school finishes, every single day", "Every morning before going to school, without fail"]}'::jsonb, '{"answer": 0, "explain": "‘después de cenar’ = after dinner. The other options invent a different time that was never said."}'::jsonb),
('spanish:x-1-listening-and-dictation:mcq:ad0c31c0', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"El sábado que viene voy a ir a un concierto.\" data-listen></span><br>Listen. What are the speaker''s plans?", "options": ["Going to a concert next Saturday", "Going to a concert last Saturday", "Staying home quietly next Saturday", "Going to a football match next Saturday evening with friends"]}'::jsonb, '{"answer": 0, "explain": "‘el sábado que viene’ = next Saturday (future); trap B swaps it to the past, trap D invents a different event."}'::jsonb),
('spanish:x-1-listening-and-dictation:mcq:b352d2e2', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Nunca voy al gimnasio porque no tengo tiempo.\" data-listen></span><br>Listen. What does the speaker say?", "options": ["They never go to the gym because they don''t have time", "They go to the gym every day because they have plenty of time", "They sometimes go to the gym at the weekend, if there''s time", "They used to go to the gym a lot but stopped last year after an injury"]}'::jsonb, '{"answer": 0, "explain": "‘nunca … no tengo tiempo’ = never … because I don''t have time. Trap B reverses both the frequency and the reason."}'::jsonb),
('spanish:x-1-listening-and-dictation:mcq:82549ee2', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Mi hermana quería ser médica, pero al final decidió estudiar para ser profesora.\" data-listen></span><br>Listen. What does the speaker''s sister want to be NOW?", "options": ["A teacher", "A doctor", "Both a doctor and a teacher at the same time", "A doctor, but only after training as a teacher first"]}'::jsonb, '{"answer": 0, "explain": "‘médica’ is mentioned only to be rejected by ‘pero al final decidió’ — the final choice is profesora (teacher)."}'::jsonb),
('spanish:x-1-listening-and-dictation:mcq:4580579d', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Mi cumpleaños es el treinta de abril.\" data-listen></span><br>Listen. When is the speaker''s birthday?", "options": ["The 30th of April", "The 13th of April", "The 30th of August", "The 3rd of April, the same day as her brother''s"]}'::jsonb, '{"answer": 0, "explain": "treinta = 30 (not trece = 13), and abril = April (not agosto = August)."}'::jsonb),
('spanish:x-1-listening-and-dictation:mcq:2f0663bb', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'mcq', 'mcq', 1, '{"question": "In the 5 minutes'' reading time before Section A starts, what is the BEST use of your time?", "options": ["Read every question and predict what kind of answer each one needs", "Write out full English sentences for every possible answer in advance", "Memorise the entire question paper word for word before listening", "Skip ahead and read only the final question, since it carries the most marks"]}'::jsonb, '{"answer": 0, "explain": "Reading and predicting turns the reading time into real preparation for the listening that follows."}'::jsonb),
('spanish:x-1-listening-and-dictation:mcq:d413a0d4', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'mcq', 'mcq', 1, '{"question": "In Section B (dictation), what should you do during the final play-through of each sentence?", "options": ["Check your spelling and add any missing accents you can hear", "Ignore it completely and move straight to the next sentence", "Translate the whole sentence into English instead of writing down the Spanish you hear", "Count how many words the sentence contains and nothing else"]}'::jsonb, '{"answer": 0, "explain": "The extra play-through exists so you can proof-read what you''ve already written, not to redo it."}'::jsonb),
('spanish:x-1-listening-and-dictation:mcq:695d5edd', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'mcq', 'mcq', 1, '{"question": "A recording mentions <span data-say=\"el fútbol\">el fútbol</span> but then adds <span data-say=\"ya no me gusta nada\" data-listen></span>. What does this test?", "options": ["Whether you notice the negative flips the meaning, so football is NOT the answer", "Whether you can spell ‘fútbol’ correctly, including the accent", "Whether you know the plural form of ‘el fútbol’", "Whether you can translate the whole sentence into perfect, fully accented Higher-tier Spanish"]}'::jsonb, '{"answer": 0, "explain": "This is exactly how a distractor works — the word is said, then rejected by the negative that follows."}'::jsonb),
('spanish:x-1-listening-and-dictation:mcq:fed48285', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Mi hermano tiene el pelo rizado y los ojos verdes.\" data-listen></span><br>Listen. What does the speaker describe?", "options": ["Their brother''s curly hair and green eyes", "Their brother''s straight hair and blue eyes", "Their sister''s curly hair and green eyes", "Their brother''s curly hair, green eyes and a small scar above one eyebrow"]}'::jsonb, '{"answer": 0, "explain": "rizado = curly, verdes = green, hermano = brother. Every distractor swaps one true detail for a false one."}'::jsonb),
('spanish:x-1-listening-and-dictation:tf:8101740d', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tf', 'tf', 1, '{"question": "Paper 1 (Listening) is worth 25% of the whole GCSE."}'::jsonb, '{"answer": true, "explain": "Correct — Listening is one of four papers, each worth 25%."}'::jsonb),
('spanish:x-1-listening-and-dictation:tf:d1117427', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tf', 'tf', 1, '{"question": "Section B (dictation) is worth more marks than Section A (comprehension)."}'::jsonb, '{"answer": false, "explain": "The opposite is true — Section A carries 32/40 marks, Section B only 8/10."}'::jsonb),
('spanish:x-1-listening-and-dictation:tf:778dfaaa', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tf', 'tf', 1, '{"question": "Listen: <span data-say=\"Voy a leer todas las preguntas antes de escuchar la grabación.\" data-listen></span> — this describes GOOD exam technique for Paper 1."}'::jsonb, '{"answer": true, "explain": "Reading every question before the recording starts is exactly the technique this page teaches."}'::jsonb),
('spanish:x-1-listening-and-dictation:tf:00d40be8', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tf', 'tf', 1, '{"question": "A negative word like ‘nunca’ or ‘no’ can completely flip the meaning of a sentence you are listening to."}'::jsonb, '{"answer": true, "explain": "This is exactly how exam recordings build distractors."}'::jsonb),
('spanish:x-1-listening-and-dictation:tf:37937109', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tf', 'tf', 1, '{"question": "Listen: <span data-say=\"Mi madre trabaja en un hospital y mi padre es profesor.\" data-listen></span> — the statement claims the speaker''s father is a teacher."}'::jsonb, '{"answer": true, "explain": "‘mi padre es profesor’ = my father is a teacher; the mother works in a hospital."}'::jsonb),
('spanish:x-1-listening-and-dictation:tf:29a322d2', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tf', 'tf', 1, '{"question": "Listen: <span data-say=\"Nunca he estudiado francés.\" data-listen></span> — this means the speaker studies French every day."}'::jsonb, '{"answer": false, "explain": "‘nunca he estudiado francés’ = I have never studied French — the exact opposite meaning."}'::jsonb),
('spanish:x-1-listening-and-dictation:tf:fb80ae89', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tf', 'tf', 1, '{"question": "In dictation, you only need to write the general meaning of the sentence, not the exact words."}'::jsonb, '{"answer": false, "explain": "Dictation requires an exact, correctly spelled transcription, not a paraphrase."}'::jsonb),
('spanish:x-1-listening-and-dictation:tf:b00693c0', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tf', 'tf', 1, '{"question": "Adding a missing accent, like on ‘está’, can matter for full marks in Higher-tier dictation."}'::jsonb, '{"answer": true, "explain": "Accents are part of correct spelling, so at Higher tier they can affect the mark."}'::jsonb),
('spanish:x-1-listening-and-dictation:learn:87682a4a', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'learn', 'mcq', 1, '{"readingTitle": "What does Paper 1 actually test?", "reading": "<p>Paper 1 is the <strong>Listening</strong> exam — a <strong>written</strong> paper: you hear a recording and write your answers straight onto the question paper. It is worth <strong>25% of your whole GCSE</strong>.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>Foundation</td><td>35 minutes, 40 marks</td></tr>\n              <tr><td>Higher</td><td>45 minutes, 50 marks</td></tr>\n            </table>\n            <p>You get <strong>5 minutes'' reading time</strong> before the recording starts, and <strong>2 minutes at the end</strong> to check your answers — use both fully. The exam has two sections: <strong>Section A</strong> (comprehension, 32/40 marks) and <strong>Section B</strong> (dictation, 8/10 marks).</p>\n            <p>Vocabulary for talking about the exam itself:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"escuchar\">escuchar</span></td><td>to listen</td><td><span data-say=\"la grabación\">la grabación</span></td><td>the recording</td></tr>\n              <tr><td><span data-say=\"comprender\">comprender</span></td><td>to understand</td><td><span data-say=\"contestar\">contestar</span></td><td>to answer</td></tr>\n            </table>", "question": "How much reading time do you get before the recording starts in Paper 1?", "options": ["5 minutes", "10 minutes", "No reading time at all — the recording starts immediately", "2 minutes, the same as the checking time at the end"]}'::jsonb, '{"answer": 0, "explain": "You get 5 minutes'' reading time before the recording starts, plus a separate 2 minutes at the end to check answers."}'::jsonb),
('spanish:x-1-listening-and-dictation:learn:5f0dff2c', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'learn', 'mcq', 1, '{"readingTitle": "Section A: how to use the reading time", "reading": "<p>Section A questions are asked <strong>in English</strong> and answered <strong>in English or non-verbally</strong> (a tick, a letter, a number). Use the 5-minute reading window to read <strong>every</strong> question first, underline the key words, and predict what TYPE of answer each one needs — a number? a reason? an opinion?</p>\n            <p>Once the recording starts, don''t try to translate word by word. Listen for whole known chunks. Example: a recording says <span data-say=\"Normalmente, veo la tele y hago mis deberes.\">Normalmente, veo la tele y hago mis deberes.</span> — even if you miss a word, recognising the chunk <span data-say=\"me gusta\">me gusta</span> (I like) or <span data-say=\"tengo que\">tengo que</span> (I have to) tells you instantly what kind of information is coming next.</p>\n            <p>The number of marks for a question tells you how many separate details are needed — a 2-mark question needs two distinct pieces of information.</p>", "question": "What is the best use of the 5-minute reading time before Section A?", "options": ["Read every question, underline key words and predict the type of answer needed", "Skip straight to writing full English sentences for every possible answer before listening", "Memorise the whole question paper word for word before listening", "Ignore the questions and just wait quietly for the recording to begin"]}'::jsonb, '{"answer": 0, "explain": "Reading and predicting first means you already know what to listen for once the audio starts."}'::jsonb),
('spanish:x-1-listening-and-dictation:learn:affe0c63', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'learn', 'mcq', 1, '{"readingTitle": "Recognising numbers, times, dates and days", "reading": "<p>Numbers, times and dates carry a lot of marks in Section A because they are precise, checkable details. Learn to recognise them <strong>instantly</strong>, without translating word by word.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el lunes\">el lunes</span></td><td>Monday</td><td><span data-say=\"el miércoles\">el miércoles</span></td><td>Wednesday</td></tr>\n              <tr><td><span data-say=\"el sábado\">el sábado</span></td><td>Saturday</td><td><span data-say=\"el domingo\">el domingo</span></td><td>Sunday</td></tr>\n              <tr><td><span data-say=\"a la una\">a la una</span></td><td>at one o''clock</td><td><span data-say=\"el mediodía\">el mediodía</span></td><td>midday</td></tr>\n              <tr><td><span data-say=\"a las ocho y media\">a las ocho y media</span></td><td>at half past eight</td><td><span data-say=\"a las diez menos cuarto\">a las diez menos cuarto</span></td><td>at quarter to ten</td></tr>\n              <tr><td><span data-say=\"el primero de enero\">el primero de enero</span></td><td>the 1st of January</td><td><span data-say=\"el treinta de abril\">el treinta de abril</span></td><td>the 30th of April</td></tr>\n            </table>\n            <p>Tip: listen for the pattern <span data-say=\"a las...\">a las…</span> for clock times, and <span data-say=\"el... de...\">el … de …</span> for dates — you don''t need every word, just spot the pattern and grab the number.</p>", "question": "Which strategy helps most when listening for a date in the recording?", "options": ["Spot the pattern ‘el … de …’ and focus on grabbing the number", "Wait for the whole sentence to be translated silently in your head first", "Only write down a date if you hear the day of the week too", "Ignore dates completely, since they are rarely worth marks"]}'::jsonb, '{"answer": 0, "explain": "Spanish dates follow a fixed pattern (el + number + de + month), so recognising the pattern lets you grab the number fast."}'::jsonb),
('spanish:x-1-listening-and-dictation:learn:b048331c', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'learn', 'mcq', 1, '{"readingTitle": "Negatives and distractors — don''t get caught out", "reading": "<p>Exam recordings are deliberately designed to include <strong>distractors</strong> — words you recognise that are <em>not</em> the answer, often because a negative flips the meaning.</p>\n            <ul>\n              <li><span data-say=\"no\">no</span> — not / no</li>\n              <li><span data-say=\"nunca\">nunca</span> — never</li>\n              <li><span data-say=\"nada\">nada</span> — nothing</li>\n              <li><span data-say=\"tampoco\">tampoco</span> — neither / not … either</li>\n            </ul>\n            <p>Example: <span data-say=\"Antes me gustaba el fútbol, pero ya no me gusta nada.\">Antes me gustaba el fútbol, pero ya no me gusta nada.</span> — <em>I used to like football, but I don''t like it at all now.</em> The recording says ‘fútbol’, but the negative at the end means it is <strong>not</strong> a current hobby.</p>\n            <p>Watch for <span data-say=\"tampoco\">tampoco</span> too: <span data-say=\"A mí tampoco me gusta la geografía.\">A mí tampoco me gusta la geografía.</span> — <em>I don''t like geography either.</em></p>", "question": "Why are negative words like ‘nunca’ or ‘no’ so important to catch while listening?", "options": ["They can completely reverse the meaning of the sentence you are listening to", "They are always the very first word in a Spanish sentence", "They only ever appear in Higher-tier recordings, never in Foundation-tier papers", "They tell you the recording has finished and it is time to write"]}'::jsonb, '{"answer": 0, "explain": "A single negative word can flip a whole sentence''s meaning, which is exactly how the exam builds distractors."}'::jsonb),
('spanish:x-1-listening-and-dictation:learn:af13e6dc', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'learn', 'mcq', 1, '{"readingTitle": "Section B: Dictation — what happens?", "reading": "<p>Section B is <strong>dictation</strong> — you hear short sentences and write down <em>exactly</em> what is said, word for word, punctuation included. It is worth <strong>8 marks at Foundation / 10 marks at Higher</strong>.</p>\n            <p>A few of the words will come from <strong>outside</strong> the GCSE vocabulary list — don''t panic, just write your best attempt using normal Spanish spelling rules; a reasonable attempt can still gain credit, but a blank cannot.</p>\n            <p>Golden rules: use the pauses to write (not to guess ahead), then use the final play-through to check spelling and add any accents you can hear.</p>\n            <p>Try it: listen to this example — <span data-say=\"Mi hermano tiene el pelo rizado y es muy simpático.\" data-listen></span> — then check: <em>Mi hermano tiene el pelo rizado y es muy simpático.</em> (My brother has curly hair and is very nice.)</p>", "question": "How many marks is Section B (dictation) worth at Foundation tier?", "options": ["8 marks", "40 marks", "0 marks — it is not assessed at Foundation", "25 marks"]}'::jsonb, '{"answer": 0, "explain": "Section B (dictation) is 8 marks at Foundation and 10 marks at Higher; Section A carries the bulk of the marks (32/40)."}'::jsonb),
('spanish:x-1-listening-and-dictation:learn:2fe779cf', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'learn', 'mcq', 1, '{"readingTitle": "Higher: matching sound to spelling in dictation", "reading": "<p><span class=\"tier-h\">H</span> Spanish spelling follows the sound closely, but these patterns catch students out in dictation:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>soft c / z</td><td><span data-say=\"cero\">cero</span>, <span data-say=\"cinco\">cinco</span>, <span data-say=\"zapato\">zapato</span> — c before e/i, and z, make a soft \"th/s\" sound</td></tr>\n              <tr><td>throaty g / j</td><td><span data-say=\"jueves\">jueves</span>, <span data-say=\"gente\">gente</span> — j always, and g before e/i, make a throaty \"h\" sound</td></tr>\n              <tr><td>silent h</td><td><span data-say=\"hermano\">hermano</span>, <span data-say=\"hay\">hay</span> — h is never pronounced, so listen for the vowel that follows</td></tr>\n              <tr><td>ñ</td><td><span data-say=\"español\">español</span>, <span data-say=\"año\">año</span> — a completely different letter to plain n</td></tr>\n              <tr><td>rr</td><td><span data-say=\"perro\">perro</span> vs <span data-say=\"pero\">pero</span> — a rolled rr changes the whole word</td></tr>\n            </table>\n            <p><span class=\"tier-h\">H</span> Add accents where you can hear the stress fall somewhere unexpected, e.g. <span data-say=\"está\">está</span>, <span data-say=\"música\">música</span> — but getting the letters right matters more than a missing accent.</p>", "question": "Why does dictation test the difference between ‘perro’ and ‘pero’?", "options": ["A rolled rr versus a single r changes the whole word and its meaning", "‘perro’ and ‘pero’ are pronounced in exactly the same way, so it never really matters", "Only Foundation students need to know this distinction", "The letters r and rr are always interchangeable in Spanish spelling"]}'::jsonb, '{"answer": 0, "explain": "perro (dog) and pero (but) sound different because of the rolled rr — writing the wrong one changes the word completely."}'::jsonb),
('spanish:x-1-listening-and-dictation:misc:da8732d3', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> In Section B, you can write a rough paraphrase of what you hear instead of the exact words.</p><p><strong>✅ The correct idea:</strong> In Section B, you must write EXACTLY what you hear, correctly spelled — dictation tests exact transcription, not paraphrase.</p>", "question": "What is required in Section B (dictation)?", "options": ["Writing exactly what you hear, spelled correctly", "Writing a rough summary in your own words", "Translating the sentence into English instead", "Writing only the first and last word of each sentence"]}'::jsonb, '{"answer": 0, "explain": "Dictation marks are for accurate transcription, not a summary or a translation."}'::jsonb),
('spanish:x-1-listening-and-dictation:misc:d2ff190e', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If a dictation sentence includes a word outside your vocabulary list, you should leave that part blank.</p><p><strong>✅ The correct idea:</strong> Even for unfamiliar words, write your best attempt using normal Spanish sound-spelling rules — a reasonable attempt can gain credit, but a blank cannot.</p>", "question": "A dictation sentence includes a word outside your vocabulary list. What should you do?", "options": ["Attempt a spelling using normal Spanish sound-spelling patterns", "Leave that part of the sentence blank since it isn''t on the list", "Write the nearest English word in its place instead", "Stop writing completely and skip to the next sentence"]}'::jsonb, '{"answer": 0, "explain": "A sensible attempt using normal Spanish spelling rules can still earn credit; a blank definitely cannot."}'::jsonb),
('spanish:x-1-listening-and-dictation:misc:e059932d', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Words like ‘no’ or ‘nunca’ are minor details you can usually skip when listening for the answer.</p><p><strong>✅ The correct idea:</strong> A negative like ‘no’ or ‘nunca’ can completely reverse a sentence''s meaning, so it is often the MOST important word to catch.</p>", "question": "Why should you never skip past a negative word while listening?", "options": ["It can completely reverse the meaning of the whole sentence", "Negatives are only ever used in Higher-tier recordings", "Negatives always come at the very start of a Spanish sentence", "Skipping negatives makes the recording easier to follow"]}'::jsonb, '{"answer": 0, "explain": "A missed negative is one of the most common reasons students pick the wrong answer in Section A."}'::jsonb),
('spanish:x-1-listening-and-dictation:misc:d9aa9686', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The 5 minutes'' reading time at the start of Paper 1 is just for reading instructions, so it barely matters.</p><p><strong>✅ The correct idea:</strong> The reading time is for reading every question and predicting what to listen for — using it well makes the actual listening much easier.</p>", "question": "What is the reading time at the start of Paper 1 actually for?", "options": ["Reading every question and predicting what kind of answer is needed", "Reading only the front-cover instructions and general exam rules, nothing else", "Filling in your name and candidate number very slowly", "Nothing important — it can safely be skipped altogether"]}'::jsonb, '{"answer": 0, "explain": "Predicting the question types before the recording starts is the whole point of the reading time."}'::jsonb),
('spanish:x-1-listening-and-dictation:misc:2d0b71f7', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Once you have written an answer in Section A, there is no need to check it again.</p><p><strong>✅ The correct idea:</strong> The 2 minutes at the end of the exam are for checking your answers make sense (an age of 200, for example, is clearly wrong) — always use them.</p>", "question": "What are the final 2 minutes of Paper 1 for?", "options": ["Checking your answers make sense and correcting obvious mistakes", "Starting Section B (dictation) again from the very beginning of the recording", "Copying your answers onto a separate answer sheet", "Nothing — the exam is effectively already finished by then"]}'::jsonb, '{"answer": 0, "explain": "The final 2 minutes exist specifically so you can catch and fix obvious errors before time is called."}'::jsonb),
('spanish:x-1-listening-and-dictation:tips:f1611706', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tips', 'mcq', 1, '{"readingTitle": "tip — Section A — predict before you listen", "reading": "Use the 5-minute reading window to read every question and predict what is coming, e.g. <span data-say=\"¿Qué le gusta hacer los fines de semana?\" data-listen></span> signals an OPINION or ACTIVITY answer is needed. Predicting the answer type before the audio starts means you already know what to listen out for.", "question": "Why predict the type of answer needed BEFORE the recording starts?", "options": ["So you already know what kind of information to listen out for", "So you can write the full answer before hearing anything in the recording at all", "Because predicting is required by the exam board''s rules", "So you can skip listening to that question altogether"]}'::jsonb, '{"answer": 0, "explain": "Predicting focuses your listening on exactly the detail the question is asking for."}'::jsonb),
('spanish:x-1-listening-and-dictation:tips:a7dc6c3f', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tips', 'mcq', 1, '{"readingTitle": "tip — Section B — dictation strategy", "reading": "Write down what you hear using normal sound-spelling rules — soft c/z, throaty g/j, silent h, ñ and rr all matter, e.g. <span data-say=\"Voy a la piscina los jueves.\" data-listen></span>. Use the final play-through only to check spelling and accents, not to rewrite from scratch.", "question": "What should the FINAL play-through of a dictation sentence be used for?", "options": ["Checking spelling and adding any accents you can hear", "Writing the sentence down completely for the very first time", "Translating the sentence into English", "Deciding whether to answer that sentence at all"]}'::jsonb, '{"answer": 0, "explain": "By the final play-through you should already have a full attempt written — it is a check, not a first draft."}'::jsonb),
('spanish:x-1-listening-and-dictation:tips:76637bc7', 'spanish', 'spanish:x-1-listening-and-dictation', 'X.1 Listening and Dictation', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Using the reading time and the checking time", "reading": "Two windows of time are easy to waste: the 5 minutes before the recording (read every question, underline key words) and the 2 minutes after (check answers make sense — <span data-say=\"Después de escuchar, tienes dos minutos para comprobar tus respuestas.\" data-listen></span>). An age of 200, or a day that doesn''t exist, is an obvious sign an answer needs another look.", "question": "Which pair of exam-time habits gets the most out of Paper 1?", "options": ["Predicting from every question first, then checking answers make sense at the end", "Listening carefully but ignoring the reading time and the final checking time completely", "Writing answers only during the checking time at the very end", "Reading the questions after the recording has already finished"]}'::jsonb, '{"answer": 0, "explain": "Both windows are graded time you are given for a reason — predicting first and checking last."}'::jsonb),
